// Package clients contains Connect client adapters for peer services.
package clients

import (
	"context"
	"net/http"

	"connectrpc.com/connect"

	// Generated by buf generate
	fieldv1 "p9e.in/samavaya/agriculture/field-service/api/v1"
	fieldv1connect "p9e.in/samavaya/agriculture/field-service/api/v1/fieldv1connect"
	"p9e.in/samavaya/agriculture/soil-service/internal/ports/outbound"
)

type fieldClient struct {
	client fieldv1connect.FieldServiceClient
}

// NewFieldClient creates a Connect-backed FieldClient.
func NewFieldClient(baseURL string, httpClient *http.Client, opts ...connect.ClientOption) outbound.FieldClient {
	return &fieldClient{
		client: fieldv1connect.NewFieldServiceClient(httpClient, baseURL, opts...),
	}
}

func (c *fieldClient) FieldExists(ctx context.Context, uuid, tenantID string) (bool, error) {
	resp, err := c.client.GetField(ctx, connect.NewRequest(&fieldv1.GetFieldRequest{Id: uuid}))
	if err != nil {
		return false, nil
	}
	return resp.Msg.GetField() != nil, nil
}
